for (const item of items) {
  // Skip items without binary data
  if (!item.binary || !item.binary.data) {
    continue;
  }

  const binary = item.binary.data;

  const fileName = binary.fileName || '';
  const extension = fileName
    .split('.')
    .pop()
    ?.toLowerCase();

  // Fix MIME type if it's octet-stream but actually a PDF
  if (
    binary.mimeType === 'application/octet-stream' &&
    extension === 'pdf'
  ) {
    binary.mimeType = 'application/pdf';
  }

  // Handle missing MIME type for PDFs
  if (!binary.mimeType && extension === 'pdf') {
    binary.mimeType = 'application/pdf';
  }
}

return items;
